def gen(rng, size):
    # build a random special (balanced, every prefix has >= ones than zeros) string
    # by recursively wrapping/concatenating, capped at length 50
    def build(budget):
        if budget < 2:
            return ''
        parts = []
        remaining = budget
        while remaining >= 2:
            inner_budget = rng.randint(0, remaining - 2)
            inner_budget -= inner_budget % 2
            chunk = '1' + build(inner_budget) + '0'
            if len(chunk) > remaining:
                break
            parts.append(chunk)
            remaining -= len(chunk)
        return ''.join(parts)
    total = rng.randint(1, 25) * 2
    s = build(total)
    if not s:
        s = '10'
    return [s]

