class Solution:
    def makeLargestSpecial(self, s):
        # independent: generate by recursion but reorder via explicit permutation-free sort with tuple key
        if len(s) <= 2:
            return s
        chunks = []
        bal = 0
        start = 0
        for i, ch in enumerate(s):
            bal += 1 if ch == '1' else -1
            if bal == 0:
                inner = self.makeLargestSpecial(s[start + 1:i])
                chunks.append('1' + inner + '0')
                start = i + 1
        chunks = sorted(chunks, reverse=True)
        return ''.join(chunks)

