var makeLargestSpecial = function(s) {
    let count = 0, i = 0;
    const subs = [];
    for (let j = 0; j < s.length; j++) {
        count += s[j] === '1' ? 1 : -1;
        if (count === 0) {
            subs.push('1' + makeLargestSpecial(s.slice(i + 1, j)) + '0');
            i = j + 1;
        }
    }
    subs.sort();
    subs.reverse();
    return subs.join('');
};
